import csv, sys; from collections import defaultdict; 
features = []; 
with open('{inputs.feature_list}') as f: reader = csv.DictReader(f) if f.readline().startswith(('m/z', 'mz', 'mass')) else csv.reader(open('{inputs.feature_list}')); f.seek(0); rows = list(csv.DictReader(f) if any(c in f.readline().lower() for c in ['m/z', 'mz', 'mass']) else csv.reader(f)); f.seek(0); 
for row in rows: 
  try: mz = float(row[0] if isinstance(row, list) else next(v for k,v in row.items() if any(x in k.lower() for x in ['m/z','mz','mass']))); features.append(mz)
  except: pass

km = 14.01565; groups = defaultdict(list); 
for mz in features: 
  kmass_exact = (mz * km) / 14.0; kmass_nominal = round(kmass_exact); kmd = kmass_exact - kmass_nominal; 
  key = round(kmd * 10000) / 10000; groups[key].append(mz)

with open('kmd_analysis_output.csv', 'w', newline='') as out: 
  w = csv.writer(out); w.writerow(['m/z', 'Kendrick_Mass', 'KMD', 'Homologous_Group']); 
  for gid, (kmd_val, mz_list) in enumerate(sorted(groups.items())): 
    for mz in sorted(mz_list): kmass = (mz * km) / 14.0; w.writerow([f'{mz:.6f}', f'{kmass:.6f}', f'{kmd_val:.6f}', f'Group_{gid}'])

print(f'KMD analysis complete: {len(features)} features in {len(groups)} homologous groups')
